+// =============================================================================
+// Q2_K Dequantization → BF16
+// =============================================================================
+// Q2_K block: 256 values packed in 84 bytes (2.96 bits per weight)
+
+struct Q2K_Block {
+    half d;           // Delta (scale)
+    half dmin;        // Min value
+    uchar scales[48]; // Per-group scales (4-bit packed)
+    uchar qs[64];     // 2-bit quantized values (packed 4 per byte)
+};
+
+constant uint Q2K_BLOCK_SIZE = 84;
+constant uint Q2K_VALUES_PER_BLOCK = 256;
+
+kernel void dequantize_q2k_bf16(
+    device const uchar* src_bytes [[buffer(0)]],
+    device bfloat16_t* dst        [[buffer(1)]],
+    constant uint& num_blocks     [[buffer(2)]],
+    uint gid                      [[thread_position_in_grid]]
+) {
+    if (gid >= num_blocks) return;
+
+    uint src_offset = gid * Q2K_BLOCK_SIZE;
+    uint dst_offset = gid * Q2K_VALUES_PER_BLOCK;
+
+    device const half* header = (device const half*)(src_bytes + src_offset);
+    float d = (float)header[0];
+    float dmin = (float)header[1];
+
+    device const uchar* scales = src_bytes + src_offset + 4;
+    device const uchar* qs = src_bytes + src_offset + 4 + 48;
+
+    for (uint i = 0; i < Q2K_VALUES_PER_BLOCK; i++) {
+        uint byte_idx = i / 4;
+        uint bit_offset = (i % 4) * 2;
+        uint q = (qs[byte_idx] >> bit_offset) & 0x3;
+
+        uint scale_idx = i / 16;
+        uint scale_byte = scales[scale_idx / 2];
+        uint scale = (scale_idx % 2 == 0) ? (scale_byte & 0xF) : (scale_byte >> 4);
+
+        float val = d * (float)scale * (float)q - dmin * (float)scale;
+        dst[dst_offset + i] = float_to_bf16(val);
+    }
+}
+

